import { Injectable, signal, computed, effect } from "@angular/core";
import type { ThemeConfig, ColorMode } from "../types";

const LIGHT_THEME_CSS = `
  :root {
    --bg-primary: #f8fafc;
    --bg-secondary: #f1f5f9;
    --bg-elevated: #ffffff;
    --bg-hover: #e2e8f0;
    --bg-active: #cbd5e1;
    --text-primary: #1e293b;
    --text-secondary: #475569;
    --text-muted: #94a3b8;
    --text-on-accent: #ffffff;
    --text-on-error: #ffffff;
    --text-on-warning: #ffffff;
    --text-on-success: #ffffff;
    --text-on-info: #ffffff;
    --border-color: #e2e8f0;
    --border-subtle: #f1f5f9;
    --accent: #3b82f6;
    --accent-hover: #2563eb;
    --accent-light: #dbeafe;
    --error: #ef4444;
    --error-light: #fee2e2;
    --warning: #f59e0b;
    --warning-light: #fef3c7;
    --success: #22c55e;
    --success-light: #dcfce7;
    --info: #06b6d4;
    --info-light: #cffafe;
    --shadow-sm: 0 1px 2px 0 rgb(0 0 0 / 0.05);
    --shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.1), 0 2px 4px -2px rgb(0 0 0 / 0.1);
    --shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.1), 0 4px 6px -4px rgb(0 0 0 / 0.1);
  }
`;

const DARK_THEME_CSS = `
  [data-theme="dark"] {
    --bg-primary: #0d1117;
    --bg-secondary: #161b22;
    --bg-elevated: #21262d;
    --bg-hover: #30363d;
    --bg-active: #484f58;
    --text-primary: #e6edf3;
    --text-secondary: #8b949e;
    --text-muted: #6e7681;
    --text-on-accent: #ffffff;
    --text-on-error: #ffffff;
    --text-on-warning: #ffffff;
    --text-on-success: #ffffff;
    --text-on-info: #ffffff;
    --border-color: #30363d;
    --border-subtle: #21262d;
    --accent: #58a6ff;
    --accent-hover: #79b8ff;
    --accent-light: #1f3d5c;
    --error: #f85149;
    --error-light: #441b1b;
    --warning: #d29922;
    --warning-light: #3d2e0a;
    --success: #3fb950;
    --success-light: #1a3d2a;
    --info: #39c5cf;
    --info-light: #0d3d40;
    --shadow-sm: 0 1px 2px 0 rgb(0 0 0 / 0.2);
    --shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.3), 0 2px 4px -2px rgb(0 0 0 / 0.2);
    --shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.4), 0 4px 6px -4px rgb(0 0 0 / 0.3);
  }
`;

@Injectable({ providedIn: "root" })
export class ThemeService {
  private readonly _colorMode = signal<ColorMode>("system");
  private readonly _resolvedMode = signal<"light" | "dark">("light");
  private readonly _accentColor = signal<string>("#3b82f6");
  private readonly _customCssVars = signal<Record<string, string>>({});
  private styleElement: HTMLStyleElement | null = null;
  private mediaQuery: MediaQueryList | null = null;

  readonly colorMode = this._colorMode.asReadonly();
  readonly resolvedMode = this._resolvedMode.asReadonly();
  readonly accentColor = this._accentColor.asReadonly();

  readonly isDark = computed(() => this._resolvedMode() === "dark");
  readonly isLight = computed(() => this._resolvedMode() === "light");

  constructor() {
    this.initTheme();
    this.setupEffect();
  }

  private initTheme(): void {
    if (typeof window === "undefined") return;

    const saved = localStorage.getItem("theme-mode") as ColorMode | null;
    if (saved && ["light", "dark", "system"].includes(saved)) {
      this._colorMode.set(saved);
    }

    const savedAccent = localStorage.getItem("theme-accent");
    if (savedAccent) {
      this._accentColor.set(savedAccent);
    }

    this.mediaQuery = window.matchMedia("(prefers-color-scheme: dark)");
    this.updateResolvedMode();
  }

  private setupEffect(): void {
    effect(() => {
      const mode = this._colorMode();
      localStorage.setItem("theme-mode", mode);
      this.updateResolvedMode();
      this.applyTheme();
    });

    effect(() => {
      const accent = this._accentColor();
      localStorage.setItem("theme-accent", accent);
      this.applyTheme();
    });
  }

  private updateResolvedMode(): void {
    const mode = this._colorMode();
    if (mode === "system") {
      const prefersDark = this.mediaQuery?.matches ?? false;
      this._resolvedMode.set(prefersDark ? "dark" : "light");
    } else {
      this._resolvedMode.set(mode);
    }
  }

  private injectStyles(): void {
    if (typeof document === "undefined") return;

    if (!this.styleElement) {
      this.styleElement = document.createElement("style");
      this.styleElement.id = "theme-service-styles";
      document.head.appendChild(this.styleElement);
    }

    let css = LIGHT_THEME_CSS + DARK_THEME_CSS;

    // Apply custom accent color
    const accent = this._accentColor();
    css += `
      :root {
        --accent: ${accent} !important;
        --accent-hover: ${this.darkenColor(accent, 15)} !important;
        --accent-light: ${this.lightenColor(accent, 85)} !important;
      }
      [data-theme="dark"] {
        --accent: ${accent} !important;
        --accent-hover: ${this.lightenColor(accent, 10)} !important;
        --accent-light: ${this.darkenColor(accent, 60)} !important;
      }
    `;

    // Apply custom CSS variables
    const customVars = this._customCssVars();
    if (Object.keys(customVars).length > 0) {
      css += `:root { ${Object.entries(customVars).map(([k, v]) => `--${k}: ${v}`).join("; ")} }`;
    }

    this.styleElement.textContent = css;
  }

  private applyTheme(): void {
    if (typeof document === "undefined") return;

    const resolved = this._resolvedMode();
    const mode = this._colorMode();

    document.body.setAttribute("data-theme", resolved);

    if (mode === "system") {
      document.body.removeAttribute("data-theme");
    }

    this.injectStyles();
  }

  toggle(): void {
    const current = this._resolvedMode();
    this._colorMode.set(current === "light" ? "dark" : "light");
  }

  setMode(mode: ColorMode): void {
    this._colorMode.set(mode);
  }

  setAccentColor(color: string): void {
    this._accentColor.set(color);
  }

  setCustomCssVariables(vars: Record<string, string>): void {
    this._customCssVars.set(vars);
    this.applyTheme();
  }

  getThemeIcon(): string {
    return this.isDark() ? "light_mode" : "dark_mode";
  }

  getCurrentTheme(): ThemeConfig {
    return {
      mode: this._colorMode(),
      accentColor: this._accentColor(),
      cssVariables: this._customCssVars(),
    };
  }

  applyThemeConfig(config: ThemeConfig): void {
    if (config.mode) this._colorMode.set(config.mode);
    if (config.accentColor) this._accentColor.set(config.accentColor);
    if (config.cssVariables) this._customCssVars.set(config.cssVariables);
  }

  private darkenColor(hex: string, percent: number): string {
    return this.adjustColor(hex, -percent);
  }

  private lightenColor(hex: string, percent: number): string {
    return this.adjustColor(hex, percent);
  }

  private adjustColor(hex: string, percent: number): string {
    const num = parseInt(hex.replace("#", ""), 16);
    const amt = Math.round(2.55 * percent);
    const R = Math.min(255, Math.max(0, (num >> 16) + amt));
    const G = Math.min(255, Math.max(0, ((num >> 8) & 0x00ff) + amt));
    const B = Math.min(255, Math.max(0, (num & 0x0000ff) + amt));
    return "#" + (0x1000000 + R * 0x10000 + G * 0x100 + B).toString(16).slice(1);
  }
}
