import { Injectable, signal, computed } from "@angular/core";
import type { ToastNotification } from "../types";

export type EventHandler = (...args: unknown[]) => void;

interface EventSubscription {
  id: string;
  event: string;
  handler: EventHandler;
  context?: unknown;
}

@Injectable({ providedIn: "root" })
export class EventBusService {
  private subscriptions = new Map<string, EventSubscription[]>();
  private eventHistory = signal<Array<{ event: string; data: unknown; timestamp: number }>>([]);
  private toastQueue = signal<ToastNotification[]>([]);
  private readonly MAX_HISTORY = 100;

  readonly history = this.eventHistory.asReadonly();
  readonly pendingToasts = this.toastQueue.asReadonly();
  readonly hasToasts = computed(() => this.toastQueue().length > 0);

  emit(event: string, data?: unknown): void {
    const timestamp = Date.now();
    this.eventHistory.update((h) => [
      ...h,
      { event, data, timestamp },
    ].slice(-this.MAX_HISTORY));

    const subs = this.subscriptions.get(event) ?? [];
    subs.forEach((sub) => {
      try {
        sub.handler.call(sub.context, data);
      } catch (err) {
        console.error(`EventBus: Error in handler for "${event}":`, err);
      }
    });
  }

  on(event: string, handler: EventHandler, context?: unknown): () => void {
    const id = `${event}-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
    const sub: EventSubscription = { id, event, handler, context };

    const existing = this.subscriptions.get(event) ?? [];
    this.subscriptions.set(event, [...existing, sub]);

    return () => this.off(event, id);
  }

  once(event: string, handler: EventHandler, context?: unknown): () => void {
    const id = `${event}-once-${Date.now()}`;
    const wrappedHandler: EventHandler = (data) => {
      handler.call(context, data);
      this.off(event, id);
    };
    const sub: EventSubscription = { id, event, handler: wrappedHandler, context };

    const existing = this.subscriptions.get(event) ?? [];
    this.subscriptions.set(event, [...existing, sub]);

    return () => this.off(event, id);
  }

  off(event: string, subscriptionId: string): void {
    const subs = this.subscriptions.get(event) ?? [];
    const filtered = subs.filter((s) => s.id !== subscriptionId);
    if (filtered.length > 0) {
      this.subscriptions.set(event, filtered);
    } else {
      this.subscriptions.delete(event);
    }
  }

  offAll(event?: string): void {
    if (event) {
      this.subscriptions.delete(event);
    } else {
      this.subscriptions.clear();
    }
  }

  hasListeners(event: string): boolean {
    const subs = this.subscriptions.get(event) ?? [];
    return subs.length > 0;
  }

  getListenerCount(event: string): number {
    return (this.subscriptions.get(event) ?? []).length;
  }

  // Toast-specific methods
  showToast(message: string, type: ToastNotification["type"] = "info", duration = 3000): string {
    const id = `toast-${Date.now()}`;
    const toast: ToastNotification = { id, message, type, duration };
    this.toastQueue.update((q) => [...q, toast]);

    if (duration > 0) {
      setTimeout(() => this.dismissToast(id), duration);
    }

    this.emit("notification", toast);
    return id;
  }

  success(message: string, duration = 3000): string {
    return this.showToast(message, "success", duration);
  }

  error(message: string, duration = 5000): string {
    return this.showToast(message, "error", duration);
  }

  warning(message: string, duration = 4000): string {
    return this.showToast(message, "warning", duration);
  }

  info(message: string, duration = 3000): string {
    return this.showToast(message, "info", duration);
  }

  dismissToast(id: string): void {
    this.toastQueue.update((q) => q.filter((t) => t.id !== id));
    this.emit("toast-dismissed", id);
  }

  dismissAllToasts(): void {
    this.toastQueue.set([]);
    this.emit("all-toasts-dismissed", undefined);
  }

  // Convenience: emit notification event (for schema-driven UI)
  notify(notification: ToastNotification): string {
    return this.showToast(notification.message, notification.type, notification.duration);
  }

  // Get toast by ID
  getToast(id: string): ToastNotification | undefined {
    return this.toastQueue().find((t) => t.id === id);
  }

  // Clear history
  clearHistory(): void {
    this.eventHistory.set([]);
  }
}

// Global window interface extension
declare global {
  interface Window {
    showToast?: (message: string, type?: ToastNotification["type"], duration?: number) => string;
    eventBus?: EventBusService;
  }
}
